theme.custom_css_code:
.bmgm-wrap{
    width:100%;
    background:transparent;
    font-family:Arial,sans-serif;
  }
  .bmgm-card{
    width:100%;
    background:#1c1d20;
    border:1px solid rgba(255,255,255,0.08);
    border-radius:20px;
    padding:22px;
    box-sizing:border-box;
    box-shadow:0 10px 30px rgba(0,0,0,0.22);
    color:#ffffff;
  }
  .bmgm-table-wrap{
    width:100%;
    overflow-x:auto;
  }
  .bmgm-table{
    width:100%;
    min-width:640px;
    border-collapse:collapse;
  }
  .bmgm-table tr:not(:last-child) td{
    border-bottom:1px solid rgba(255,255,255,0.08);
  }
  .bmgm-table td{
    padding:14px 16px;
    font-size:15px;
    line-height:1.45;
    vertical-align:top;
  }
  .bmgm-table td:first-child{
    width:34%;
    color:rgba(255,255,255,0.68);
    font-weight:600;
  }
  .bmgm-chart{
    width:100%;
  }
  .bmgm-chart-head{
    display:flex;
    flex-direction:column;
    gap:6px;
    margin-bottom:18px;
  }
  .bmgm-chart-title{
    font-size:22px;
    line-height:1.2;
    font-weight:700;
    color:#ffffff;
  }
  .bmgm-chart-subtitle{
    font-size:14px;
    line-height:1.4;
    color:rgba(255,255,255,0.62);
  }
  .bmgm-bars,
  .bmgm-compare{
    display:flex;
    flex-direction:column;
    gap:14px;
  }
  .bmgm-row{
    display:grid;
    grid-template-columns:140px minmax(0,1fr) 44px;
    gap:14px;
    align-items:center;
  }
  .bmgm-label,
  .bmgm-compare-label{
    font-size:14px;
    line-height:1.3;
    color:#ffffff;
  }
  .bmgm-bar-track,
  .bmgm-compare-track{
    position:relative;
    width:100%;
    height:14px;
    border-radius:999px;
    background:rgba(255,255,255,0.09);
    overflow:hidden;
  }
  .bmgm-bar-fill,
  .bmgm-compare-fill{
    height:100%;
    border-radius:999px;
    background:linear-gradient(90deg,#a3ff3f 0%,#5ed46f 100%);
  }
  .bmgm-value{
    text-align:right;
    font-size:13px;
    color:rgba(255,255,255,0.7);
    font-weight:700;
  }
  .bmgm-compare-row{
    display:grid;
    grid-template-columns:150px minmax(0,1fr);
    gap:16px;
    align-items:center;
  }
  .bmgm-compare-bars{
    display:grid;
    grid-template-columns:1fr 1fr;
    gap:10px;
  }
  .bmgm-brand{
    background:linear-gradient(90deg,#f8ff5a 0%,#94f152 100%);
  }
  .bmgm-market{
    background:linear-gradient(90deg,#6d727b 0%,#9aa0aa 100%);
  }
  .bmgm-legend{
    display:flex;
    flex-wrap:wrap;
    gap:18px;
    margin-top:18px;
  }
  .bmgm-legend-item{
    display:inline-flex;
    align-items:center;
    gap:8px;
    font-size:13px;
    color:rgba(255,255,255,0.72);
  }
  .bmgm-dot{
    width:10px;
    height:10px;
    border-radius:50%;
    display:inline-block;
  }
  @media (max-width:767px){
    .bmgm-card{
      padding:18px;
      border-radius:16px;
    }
    .bmgm-row{
      grid-template-columns:1fr;
      gap:8px;
    }
    .bmgm-value{
      text-align:left;
    }
    .bmgm-compare-row{
      grid-template-columns:1fr;
      gap:10px;
    }
    .bmgm-compare-bars{
      grid-template-columns:1fr;
    }
    .bmgm-chart-title{
      font-size:20px;
    }
    .bmgm-table{
      min-width:560px;
    }
  }
